SELECT ifnull(COUNT(*), '0') as 'orgNum'
from sys_organization a
         left join pr_data_grant b on b.org_id = a.id and b.user_id = #{userId}
where a.company_id = #{companyId}
  and a.level = 2
  and b.user_id = #{userId}

SELECT ifnull(count(1),0) as 'orgStationNum' FROM pr_data_grant a
LEFT JOIN pr_heat_station_org b on a.org_id = b.org_id
where a.user_id = #{userId}

    and b.station_id=#{stationId}

select ifnull(count(1),0) as 'buildingNum' from (
SELECT DISTINCT a.id from pr_building a
INNER JOIN pr_heat_station b on a.company_id=b.company_id and a.station_id=b.id
INNER JOIN pr_heat_station_partition c on c.station_id=b.id
INNER join pr_data_grant d on d.org_id=a.org_id and d.user_id=#{userId}
where a.company_id=#{companyId} and a.is_deleted='0' and d.user_id=#{userId}

    and b.id=#{stationId}

) x

select ifnull(count(1),0) as 'buildingAllNum' from (
SELECT DISTINCT a.id from pr_building a
INNER JOIN pr_heat_station b on a.company_id=b.company_id and a.station_id=b.id
INNER JOIN pr_heat_station_partition c on c.station_id=b.id
INNER join pr_data_grant d on d.org_id=a.org_id and d.user_id=#{userId}
where a.company_id=#{companyId} and a.is_deleted='0' and d.user_id=#{userId}
) x

SELECT ifnull(COUNT(*),'0') as 'houseNum' from pr_house a
LEFT JOIN pr_heat_station_partition c on c.id=a.station_type and a.company_id=c.company_id
LEFT JOIN pr_heat_station b on c.station_id=b.id
left join pr_data_grant d on d.org_id=a.org_id and d.user_id=#{userId}
where a.company_id=#{companyId} and a.is_deleted='0' and d.user_id=#{userId}

    and b.id=#{stationId}


    and c.id=#{stationPartitionId}

SELECT ifnull(COUNT(*), '0') as 'prUserNum'
FROM pr_house a
