where a.company_id = #{companyId}
  and a.is_deleted = '0'
  and d.user_id = #{userId}

SELECT ifnull(SUM(a.heating_area),'0') as 'heatingArea' from pr_house a
INNER JOIN pr_heat_station_partition c on c.id=a.station_type and a.company_id=c.company_id
INNER JOIN pr_heat_station b on c.station_id=b.id
INNER join pr_data_grant d on d.org_id=a.org_id and d.user_id=#{userId}
where a.company_id=#{companyId} and a.is_deleted='0' and d.user_id=#{userId}

    and b.id=#{stationId}


    and c.id=#{stationPartitionId}

SELECT ifnull(SUM(a.heating_area),'0') as 'heatingAreaSum' from pr_house a
INNER JOIN pr_heat_station_partition c on c.id=a.station_type and a.company_id=c.company_id
INNER JOIN pr_heat_station b on c.station_id=b.id
INNER join pr_data_grant d on d.org_id=a.org_id and d.user_id=#{userId}
where a.company_id=#{companyId} and a.is_deleted='0' and d.user_id=#{userId}

SELECT ifnull(COUNT(*),'0') as 'valveNum' from pr_heat_valve_archive a
LEFT JOIN pr_house b on b.id=a.house_id
LEFT JOIN pr_heat_station_partition c on c.id=b.station_type and b.company_id=c.company_id
LEFT JOIN pr_heat_station d on c.station_id=d.id
left join pr_data_grant e on e.org_id=a.org_id and e.user_id=#{userId}
where a.company_id=#{companyId} and a.is_changed='0' and b.is_deleted='0' and e.user_id=#{userId}

    and d.id=#{stationId}


    and c.id=#{stationPartitionId}

SELECT ifnull(COUNT(*),'0') as 'valveNum' from pr_heat_valve_archive a
LEFT JOIN pr_house b on b.id=a.house_id
LEFT JOIN pr_heat_station_partition c on c.id=b.station_type and b.company_id=c.company_id
LEFT JOIN pr_heat_station d on c.station_id=d.id
left join pr_data_grant e on e.org_id=a.org_id and e.user_id=#{userId}
where a.company_id=#{companyId} and a.is_changed='0' and b.is_deleted='0' and e.user_id=#{userId} and
(a.valve_status in (1,2) or a.valve_status is null)

    and d.id=#{stationId}


    and c.id=#{stationPartitionId}

