SELECT ifnull(COUNT(*),'0') as 'tempArchiveNum' from pr_heat_temp_archive a
LEFT JOIN pr_house b on b.id=a.house_id
LEFT JOIN pr_heat_station_partition c on c.id=b.station_type and b.company_id=c.company_id
LEFT JOIN pr_heat_station d on c.station_id=d.id
left join pr_data_grant e on e.org_id=a.org_id
where a.company_id=#{companyId} and a.is_changed='0' and b.is_deleted='0' and e.user_id=#{userId}

    and d.id=#{stationId}


    and c.id=#{stationPartitionId}

SELECT ifnull(COUNT(*),'0') as 'tempArchiveNum' from pr_heat_temp_archive a LEFT JOIN pr_house b on b.id=a.house_id LEFT JOIN pr_heat_station_partition c on c.id=b.station_type and b.company_id=c.company_id LEFT JOIN pr_heat_station d on c.station_id=d.id left join pr_data_grant e on e.org_id=a.org_id where a.company_id=#{companyId} and a.is_changed='0' and b.is_deleted='0' and e.user_id=#{userId} AND ( a.valve_status IS NULL OR LENGTH( a.valve_status ) != 4 OR ( CASE WHEN -- 判断左起第 15、14、8、7、6、5、0 位是否为 1 ( SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 1, 1 ) = '1' AND -- 第15位 SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 2, 1 ) = '1' AND -- 第14位 SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 9, 1 ) = '1' AND -- 第8位 SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 10, 1 ) = '1' AND -- 第7位 SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 11, 1 ) = '1' AND -- 第6位 SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 12, 1 ) = '1' AND -- 第5位 SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 16, 1 ) = '1' ) -- 第0位
OR -- 判断左起第 4 和 3 位是 01 或 10 ( SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 10, 2 ) IN ( '01', '10' )) OR -- 判断左起第 2 和 1 位是 01 或 10 ( SUBSTRING( BIN( CONV( valve_status, 16, 10 )), 12, 2 ) IN ( '01', '10' )) THEN - 1 ELSE 1 END ) = 1 )
and d.id=#{stationId}
and c.id=#{stationPartitionId}

SELECT a.meter_arc_name as 'name',ifnull(COUNT(*),'0') as 'value' from pr_heat_temp_archive a
LEFT JOIN pr_house b on b.id=a.house_id
