    and d.id=#{stationId}


    and c.id=#{stationPartitionId}

SELECT JSON_ARRAYAGG(JSON_OBJECT( 'stationId', a2.id, 'stationName', a2.name, 'stationPartitionId', a1.id, 'stationPartitionName', a1.name, 'outTemperature', a1.out_temperature, 'stationPCount', a1.stationPCount, 'phCount', a1.phCount )) AS jsonResult FROM ( SELECT t2.id, t2.station_id, t2.name, SUM(t4.out_temperature) AS out_temperature, SUM(case when t4.out_temperature <= (t6.mrphwd + t6.hswdpcz) AND t4.out_temperature >= (t6.mrphwd - t6.hswdpcz)then 1 else 0 end) as phCount, SUM(CASE WHEN t1.is_special = '0' THEN 1 ELSE 0 END) AS stationPCount FROM pr_house t1 INNER JOIN pr_heat_station_partition t2 ON t1.station_type = t2.id INNER JOIN pr_heat_valve_archive t4 ON t1.id = t4.house_id INNER JOIN pr_data_grant t5 ON t5.org_id = t1.org_id INNER JOIN pr_options_heat t6 ON t5.company_id = t6.company_id and t6.org_id is null and t6.mrphwd > 0 and t6.hswdpcz > 0 WHERE t2.is_deleted = '0' AND t1.is_deleted = 0 AND t1.pay_status = 1 AND t4.out_temperature > 0 AND t4.is_changed = '0' AND t1.is_deleted = '0' AND t5.user_id = #{userId}
AND t2.id = #{stationPartitionId}
AND t2.station_id = #{stationId}
GROUP BY t2.id, t2.station_id, t2.name ) a1 INNER JOIN pr_heat_station a2 ON a1.station_id = a2.ID ORDER BY a2.id, a1.id
